import json, re
# Load all citation records
path_all = var_call_eg8rP1RmWgqRjk1wBHSbX67d
with open(path_all, 'r', encoding='utf-8') as f:
    records = json.load(f)
# UC publication numbers from previous run
uc_pubs = var_call_zYTqAsAwP0cMuZXGUt98Gq8X
uc_set = set(uc_pubs)

# helper to parse citation field which may be JSON string
def parse_citation_field(cit):
    if not cit:
        return []
    try:
        return json.loads(cit)
    except Exception:
        # try to fix single quotes
        try:
            return json.loads(cit.replace("'", '"'))
        except Exception:
            return []

# helper to extract assignee from Patents_info
def extract_assignee(pi):
    if not pi:
        return None
    pi = pi.strip()
    # Try patterns
    patterns = [
        r"^([A-Z0-9 &.,'-]+?) holds\b",
        r"\b(is owned by|owned by|assigned to|is assigned to|is held by|held by) ([A-Z0-9 &.,'/-]+?)(?: and |,| with | has |\(|$)",
        r"\b(owner|owner:) ([A-Z0-9 &.,'/-]+?)(?: and |,| with | has |\(|$)",
        r"^([A-Z0-9 &.,'-]+?) has\b",
    ]
    for pat in patterns:
        m = re.search(pat, pi, flags=re.IGNORECASE)
        if m:
            if len(m.groups())==1:
                name = m.group(1)
            else:
                name = m.group(len(m.groups()))
            name = name.strip()
            # cleanup trailing words
            name = re.sub(r"\b(the|a|an)\b$", '', name, flags=re.IGNORECASE).strip()
            return name.upper()
    # fallback: look for 'by <NAME>'
    m = re.search(r"by ([A-Z0-9 &.,'/-]+?)(?: and |,| with | has |\(|$)", pi, flags=re.IGNORECASE)
    if m:
        return m.group(1).strip().upper()
    # otherwise take first uppercase words before a verb
    m = re.match(r"^([A-Z0-9 &.,'-]{3,40})", pi)
    if m:
        return m.group(1).strip().upper()
    return None

assignee_map = {}
unique_codes = set()

for rec in records:
    cit_list = parse_citation_field(rec.get('citation'))
    cites_uc = False
    for c in cit_list:
        pubnum = c.get('publication_number') if isinstance(c, dict) else None
        if not pubnum:
            continue
        pubnum = pubnum.strip()
        if pubnum in uc_set:
            cites_uc = True
            break
    if not cites_uc:
        continue
    # get assignee
    pi = rec.get('Patents_info','')
    assignee = extract_assignee(pi)
    if not assignee:
        assignee = 'UNKNOWN'
    # skip if assignee is UNIV CALIFORNIA
    if 'UNIV CALIFORNIA' in assignee:
        continue
    # parse cpc
    cpc_field = rec.get('cpc')
    codes = []
    try:
        cpcs = json.loads(cpc_field) if cpc_field else []
    except Exception:
        try:
            cpcs = json.loads(cpc_field.replace("'", '"'))
        except Exception:
            cpcs = []
    primary_codes = [entry.get('code') for entry in cpcs if entry.get('first')]
    if not primary_codes and cpcs:
        # take first element's code
        code0 = cpcs[0].get('code')
        if code0:
            primary_codes = [code0]
    # normalize codes
    primary_codes = [c.strip().upper() for c in primary_codes if c]
    if not primary_codes:
        primary_codes = ['UNKNOWN']
    if assignee not in assignee_map:
        assignee_map[assignee] = set()
    for pc in primary_codes:
        assignee_map[assignee].add(pc)
        if pc != 'UNKNOWN':
            unique_codes.add(pc)

# convert sets to lists
out = []
for a, codes in assignee_map.items():
    out.append({'assignee': a, 'cpc_codes': sorted(codes)})
unique_codes = sorted(unique_codes)

print("__RESULT__:")
print(json.dumps({'assignee_map': out, 'unique_codes': unique_codes}))

