import json, re
path_records = var_call_eg8rP1RmWgqRjk1wBHSbX67d
path_uc = var_call_zYTqAsAwP0cMuZXGUt98Gq8X
with open(path_records, 'r', encoding='utf-8') as f:
    records = json.load(f)
uc_pubs = set(path_uc)
# normalize function
import re
def norm(s):
    if not s: return ''
    return re.sub(r'[^A-Z0-9]', '', s.upper())
uc_norm = set(norm(p) for p in uc_pubs)

matches = []

for rec in records:
    cit = rec.get('citation')
    if not cit: continue
    try:
        cit_list = json.loads(cit)
    except Exception:
        try:
            cit_list = json.loads(cit.replace("'", '"'))
        except Exception:
            cit_list = []
    found = False
    for c in cit_list:
        if not isinstance(c, dict):
            continue
        pub = c.get('publication_number')
        if not pub: continue
        if norm(pub) in uc_norm:
            found = True
            break
    if not found: continue
    # extract assignee
    pi = rec.get('Patents_info','')
    assignee = None
    # patterns
    pats = [
        r"\b(?:is owned by|owned by|is assigned to|assigned to|is held by|held by|is owned by|owned by|belongs to|is belonging to)\s+([A-Z0-9 &.,'/-]{2,120})",
        r"^([A-Z0-9 &.,'/-]{2,120})\s+(?:holds|has|own|owns|owned)\b",
        r"\b([A-Z0-9 &.,'/-]{2,120})\s+holds the\b",
        r"\b([A-Z0-9 &.,'/-]{2,120})\s+holds\b",
    ]
    for p in pats:
        m = re.search(p, pi, flags=re.IGNORECASE)
        if m:
            assignee = m.group(1).strip()
            break
    if not assignee:
        # fallback: take all caps word sequences at start
        m = re.match(r"^([A-Z][A-Z &.,'/-]{2,60})", pi)
        if m:
            assignee = m.group(1).strip()
    if not assignee:
        assignee = 'UNKNOWN'
    assignee = assignee.upper()
    # parse cpc
    cpc_field = rec.get('cpc')
    primary_codes = []
    if cpc_field:
        try:
            cpcs = json.loads(cpc_field)
        except Exception:
            try:
                cpcs = json.loads(cpc_field.replace("'", '"'))
            except Exception:
                cpcs = []
        for e in cpcs:
            if isinstance(e, dict) and e.get('first'):
                code = e.get('code')
                if code:
                    primary_codes.append(code.strip().upper())
        if not primary_codes and cpcs:
            e = cpcs[0]
            if isinstance(e, dict):
                code = e.get('code')
                if code:
                    primary_codes = [code.strip().upper()]
    if not primary_codes:
        primary_codes = ['UNKNOWN']
    matches.append({'assignee': assignee, 'primary_cpcs': sorted(set(primary_codes)), 'Patents_info': pi[:200]})

# deduplicate by assignee
out_map = {}
for m in matches:
    a = m['assignee']
    if 'UNIV CALIFORNIA' in a:
        continue
    out_map.setdefault(a, set()).update(m['primary_cpcs'])

out = [{'assignee': a, 'cpc_codes': sorted(list(codes))} for a,codes in out_map.items()]

print('__RESULT__:')
print(json.dumps({'count_matches': len(matches), 'unique_assignees': len(out), 'assignees': out[:200]}))

