import json, re, os
all_path = var_call_eg8rP1RmWgqRjk1wBHSbX67d
uc_pubs = var_call_zYTqAsAwP0cMuZXGUt98Gq8X
# load all records
with open(all_path, 'r', encoding='utf-8') as f:
    all_records = json.load(f)

# normalize helper
def norm(s):
    return re.sub('[^A-Z0-9]','', (s or '').upper())
uc_norm = set(norm(p) for p in uc_pubs)

def citation_contains_uc(citation_text):
    if not citation_text:
        return False
    s = norm(citation_text)
    for up in uc_norm:
        if up and up in s:
            return True
    return False

def extract_assignee_simple(pi):
    if not pi:
        return 'UNKNOWN'
    su = pi.strip()
    su_up = su.upper()
    m = re.match('^([A-Z0-9 &.,\'"\-/]{2,120})\\s+(HOLDS|HAS|HOLD|IS|OWN|OWNS|OWNED|ASSIGNED|BELONGS|IS OWNED)', su_up)
    if m:
        return m.group(1).strip()
    # look for 'assigned to X' pattern
    m = re.search('ASSIGNED TO\s+([A-Z0-9 &.,\'"\-/]{2,120})', su_up)
    if m:
        return m.group(1).strip()
    # fallback: take leading words before '(' or ','
    m = re.split('[,(]', su_up)
    if m and m[0]:
        return m[0].strip()
    return su_up

assignee_map = {}
unique_codes = set()

for rec in all_records:
    cit = rec.get('citation')
    if not cit:
        continue
    if not citation_contains_uc(cit):
        continue
    # get assignee
    assignee = extract_assignee_simple(rec.get('Patents_info',''))
    if 'UNIV CALIFORNIA' in assignee:
        continue
    # parse cpc
    primary = []
    cpc_field = rec.get('cpc')
    if cpc_field:
        try:
            cpcs = json.loads(cpc_field) if isinstance(cpc_field,str) else cpc_field
        except Exception:
            try:
                cpcs = json.loads(cpc_field.replace("'", '"'))
            except Exception:
                cpcs = []
        if isinstance(cpcs, list) and cpcs:
            for e in cpcs:
                if isinstance(e, dict) and e.get('first'):
                    code = e.get('code')
                    if code:
                        primary.append(code.strip().upper())
            if not primary:
                e = cpcs[0]
                if isinstance(e, dict):
                    code = e.get('code')
                    if code:
                        primary = [code.strip().upper()]
    if not primary:
        primary = ['UNKNOWN']
    assignee_map.setdefault(assignee, set()).update(primary)
    for pc in primary:
        if pc and pc!='UNKNOWN':
            unique_codes.add(pc)

out = [{'assignee': a, 'cpc_codes': sorted(list(codes))} for a,codes in assignee_map.items()]
result = {'assignees': out, 'unique_cpc_codes': sorted(list(unique_codes)), 'num_assignees': len(out)}
print('__RESULT__:')
print(json.dumps(result))

